mapper.select:
SELECT DATE(create_time) AS date, COUNT(*) AS orderCount, COALESCE(SUM( CASE WHEN status >= 1 AND status != 5 THEN total_amount ELSE 0 END ), 0) AS sales, SUM(CASE WHEN status = 4 THEN 1 ELSE 0 END) AS completedCount, SUM(CASE WHEN status = 5 THEN 1 ELSE 0 END) AS cancelledCount FROM orders WHERE create_time BETWEEN #{startTime} AND #{endTime}
AND store_id = #{storeId}
GROUP BY DATE(create_time) ORDER BY date
